import type { MittwaldCliToolHandler } from '../../../../types/mittwald/conversation.js';
import { formatToolResponse } from '../../../../utils/format-tool-response.js';
import { invokeCliTool, CliToolError } from '../../../../tools/index.js';

interface MittwaldDomainVirtualhostListArgs {
  projectId?: string;
  all?: boolean;
  output?: 'txt' | 'json' | 'yaml' | 'csv' | 'tsv';
  extended?: boolean;
  noHeader?: boolean;
  noTruncate?: boolean;
  noRelativeDates?: boolean;
  csvSeparator?: ',' | ';';
}

function buildCliArgs(args: MittwaldDomainVirtualhostListArgs): string[] {
  const cliArgs: string[] = ['domain', 'virtualhost', 'list'];

  cliArgs.push('--output', 'json');

  if (args.projectId) cliArgs.push('--project-id', args.projectId);
  if (args.all) cliArgs.push('--all');
  if (args.extended) cliArgs.push('--extended');
  if (args.noHeader) cliArgs.push('--no-header');
  if (args.noTruncate) cliArgs.push('--no-truncate');
  if (args.noRelativeDates) cliArgs.push('--no-relative-dates');
  if (args.csvSeparator) cliArgs.push('--csv-separator', args.csvSeparator);

  return cliArgs;
}

type RawVirtualhostListItem = {
  id?: string;
  hostname?: string;
  projectId?: string;
  paths?: unknown;
  status?: string;
  ips?: unknown;
};

interface ParsedVirtualhostListResult {
  items?: RawVirtualhostListItem[];
  error?: string;
}

function parseVirtualhostList(output: string): ParsedVirtualhostListResult {
  if (!output) return { items: undefined };

  try {
    const parsed = JSON.parse(output);
    return Array.isArray(parsed) ? { items: parsed } : { error: 'Unexpected output format from CLI command' };
  } catch (error) {
    return { error: error instanceof Error ? error.message : String(error) };
  }
}

function mapCliError(error: CliToolError, args: MittwaldDomainVirtualhostListArgs): string {
  const combined = `${error.stderr ?? ''} ${error.stdout ?? ''}`.toLowerCase();

  if (combined.includes('not found') && combined.includes('project')) {
    return `Project not found. Please verify the project ID: ${args.projectId ?? 'not specified'}.\nError: ${error.stderr || error.message}`;
  }

  return error.message;
}

export const handleDomainVirtualhostListCli: MittwaldCliToolHandler<MittwaldDomainVirtualhostListArgs> = async (args) => {
  const argv = buildCliArgs(args);

  try {
    const result = await invokeCliTool({
      toolName: 'mittwald_domain_virtualhost_list',
      argv,
      parser: (stdout, raw) => ({ stdout, stderr: raw.stderr }),
    });

    const stdout = result.result.stdout ?? '';
    const stderr = result.result.stderr ?? '';
    const { items, error: parseError } = parseVirtualhostList(stdout);

    if (!items) {
      return formatToolResponse(
        'success',
        'Virtual hosts retrieved (raw output)',
        {
          rawOutput: stdout,
          stderr,
          parseError,
        },
        {
          command: result.meta.command,
          durationMs: result.meta.durationMs,
        }
      );
    }

    if (items.length === 0) {
      return formatToolResponse(
        'success',
        'No virtual hosts found',
        [],
        {
          command: result.meta.command,
          durationMs: result.meta.durationMs,
        }
      );
    }

    const formattedData = items.map((item) => ({
      id: item.id,
      hostname: item.hostname,
      projectId: item.projectId,
      paths: item.paths,
      status: item.status,
      ips: item.ips,
    }));

    return formatToolResponse(
      'success',
      `Found ${formattedData.length} virtual host(s)`,
      formattedData,
      {
        command: result.meta.command,
        durationMs: result.meta.durationMs,
      }
    );
  } catch (error) {
    if (error instanceof CliToolError) {
      const message = mapCliError(error, args);
      return formatToolResponse('error', message, {
        exitCode: error.exitCode,
        stderr: error.stderr,
        stdout: error.stdout,
        suggestedAction: error.suggestedAction,
      });
    }

    return formatToolResponse('error', `Failed to execute CLI command: ${error instanceof Error ? error.message : String(error)}`);
  }
};
